@Service
class SamlKeyService {
    private final SamlProperties props;
    private BasicX509Credential credential;

    SamlKeyService(SamlProperties props) {
        this.props = props;
    }

    @PostConstruct
    public void load() throws Exception {
        KeyStore ks = KeyStore.getInstance("JKS");
        try (InputStream is = props.getKeystoreLocation().getInputStream()) {
            ks.load(is, props.getKeystorePassword().toCharArray());
        }
        PrivateKey privateKey = (PrivateKey) ks.getKey(props.getKeystoreAlias(), props.getKeyPassword().toCharArray());
        JX509Certificate cert = (JX509Certificate) ks.getCertificate(props.getKeystoreAlias());
        credential = new BasicX509Credential(cert, privateKey);
    }

    public BasicX509Credential getCredential() {
        return credential;
    }

    public JX509Certificate getCertificate() {
        return credential.getEntityCertificate();
    }
}

@Service
class SamlMessageService {
    private final SamlProperties props;
    private final SamlKeyService keyService;

    SamlMessageService(SamlProperties props, SamlKeyService keyService) {
        this.props = props;
        this.keyService = keyService;
    }

    public String buildAuthnRequest(String relayState) throws Exception {
        AuthnRequest request = (AuthnRequest) XMLObjectSupport.buildXMLObject(AuthnRequest.DEFAULT_ELEMENT_NAME);
        request.setID("_" + UUID.randomUUID());
        request.setVersion(SAMLVersion.VERSION_20);
        request.setIssueInstant(Instant.now());
        request.setDestination(props.getIdpSsoUrl());
        request.setAssertionConsumerServiceURL(props.getAcsUrl());
        request.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);

        Issuer issuer = (Issuer) XMLObjectSupport.buildXMLObject(Issuer.DEFAULT_ELEMENT_NAME);
        issuer.setValue(props.getEntityId());
        request.setIssuer(issuer);

        NameIDPolicy nameIDPolicy = (NameIDPolicy) XMLObjectSupport.buildXMLObject(NameIDPolicy.DEFAULT_ELEMENT_NAME);
        nameIDPolicy.setAllowCreate(true);
        nameIDPolicy.setFormat(NameIDType.PERSISTENT);
        request.setNameIDPolicy(nameIDPolicy);

        RequestedAuthnContext rac = (RequestedAuthnContext) XMLObjectSupport.buildXMLObject(RequestedAuthnContext.DEFAULT_ELEMENT_NAME);
        AuthnContextClassRef acr = (AuthnContextClassRef) XMLObjectSupport.buildXMLObject(AuthnContextClassRef.DEFAULT_ELEMENT_NAME);
        acr.setURI(AuthnContext.PASSWORD_AUTHN_CTX);
        rac.getAuthnContextClassRefs().add(acr);
        rac.setComparison(AuthnContextComparisonTypeEnumeration.EXACT);
        request.setRequestedAuthnContext(rac);

        String xml = XMLObjectSupport.marshallToString(request);
        String deflated = deflateAndBase64(xml);
        return UriComponentsBuilder.fromHttpUrl(props.getIdpSsoUrl())
                .queryParam("SAMLRequest", deflated)
                .queryParam("RelayState", relayState)
                .build(true)
                .toUriString();
    }

    public String buildMetadata() throws Exception {
        EntityDescriptor entityDescriptor = (EntityDescriptor) XMLObjectSupport.buildXMLObject(EntityDescriptor.DEFAULT_ELEMENT_NAME);
        entityDescriptor.setEntityID(props.getEntityId());

        SPSSODescriptor sp = (SPSSODescriptor) XMLObjectSupport.buildXMLObject(SPSSODescriptor.DEFAULT_ELEMENT_NAME);
        sp.addSupportedProtocol(SAMLConstants.SAML20P_NS);

        NameIDFormat nif = (NameIDFormat) XMLObjectSupport.buildXMLObject(NameIDFormat.DEFAULT_ELEMENT_NAME);
        nif.setFormat(NameIDType.PERSISTENT);
        sp.getNameIDFormats().add(nif);

        AssertionConsumerService acs = (AssertionConsumerService) XMLObjectSupport.buildXMLObject(AssertionConsumerService.DEFAULT_ELEMENT_NAME);
        acs.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acs.setLocation(props.getAcsUrl());
        acs.setIndex(0);
        acs.setIsDefault(true);
        sp.getAssertionConsumerServices().add(acs);

        SingleLogoutService slo = (SingleLogoutService) XMLObjectSupport.buildXMLObject(SingleLogoutService.DEFAULT_ELEMENT_NAME);
        slo.setBinding(SAMLConstants.SAML2_REDIRECT_BINDING_URI);
        slo.setLocation(props.getSloUrl());
        sp.getSingleLogoutServices().add(slo);

        KeyDescriptor kd = (KeyDescriptor) XMLObjectSupport.buildXMLObject(KeyDescriptor.DEFAULT_ELEMENT_NAME);
        kd.setUse(UsageType.SIGNING);
        org.opensaml.xmlsec.signature.KeyInfo keyInfo = (org.opensaml.xmlsec.signature.KeyInfo) XMLObjectSupport.buildXMLObject(org.opensaml.xmlsec.signature.KeyInfo.DEFAULT_ELEMENT_NAME);
        org.opensaml.xmlsec.signature.X509Data x509Data = (org.opensaml.xmlsec.signature.X509Data) XMLObjectSupport.buildXMLObject(org.opensaml.xmlsec.signature.X509Data.DEFAULT_ELEMENT_NAME);
        org.opensaml.xmlsec.signature.X509Certificate x509Cert = (org.opensaml.xmlsec.signature.X509Certificate) XMLObjectSupport.buildXMLObject(org.opensaml.xmlsec.signature.X509Certificate.DEFAULT_ELEMENT_NAME);
        x509Cert.setValue(Base64.getEncoder().encodeToString(keyService.getCertificate().getEncoded()));
        x509Data.getX509Certificates().add(x509Cert);
        keyInfo.getX509Datas().add(x509Data);
        kd.setKeyInfo(keyInfo);
        sp.getKeyDescriptors().add(kd);

        entityDescriptor.getRoleDescriptors().add(sp);
        return XMLObjectSupport.marshallToString(entityDescriptor);
    }

    public String parseAndValidateSamlResponse(String samlResponseBase64) throws Exception {
        byte[] decoded = Base64.getDecoder().decode(samlResponseBase64);
        String xml = new String(decoded, StandardCharsets.UTF_8);
        XMLObject xmlObject = XMLObjectSupport.unmarshallFromInputStream(XMLObjectProviderRegistrySupport.getParserPool(), new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
        if (!(xmlObject instanceof Response response)) {
            throw new IllegalArgumentException("Invalid SAML Response");
        }
        if (response.getStatus() == null || response.getStatus().getStatusCode() == null || !StatusCode.SUCCESS.equals(response.getStatus().getStatusCode().getValue())) {
            throw new IllegalArgumentException("SAML Response not successful");
        }
        if (response.getAssertions().isEmpty()) {
            throw new IllegalArgumentException("No assertions found");
        }
        Assertion assertion = response.getAssertions().get(0);
        if (assertion.getSubject() == null || assertion.getSubject().getNameID() == null) {
            throw new IllegalArgumentException("Missing subject");
        }
        String username = assertion.getSubject().getNameID().getValue();
        Map<String, String> attrs = new LinkedHashMap<>();
        if (assertion.getAttributeStatements() != null) {
            for (AttributeStatement stmt : assertion.getAttributeStatements()) {
                for (Attribute attr : stmt.getAttributes()) {
                    StringBuilder sb = new StringBuilder();
                    for (XMLObject val : attr.getAttributeValues()) {
                        sb.append(val.getDOM() != null ? val.getDOM().getTextContent() : val.toString()).append(",");
                    }
                    attrs.put(attr.getName(), sb.toString());
                }
            }
        }
        return "user=" + username + ";attrs=" + attrs;
    }

    private String deflateAndBase64(String xml) throws Exception {
        byte[] input = xml.getBytes(StandardCharsets.UTF_8);
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        deflater.setInput(input);
        deflater.finish();
        byte[] buffer = new byte[8192];
        int len = deflater.deflate(buffer);
        deflater.end();
        return Base64.getEncoder().encodeToString(Arrays.copyOf(buffer, len));
    }
}

@RestController
@RequestMapping("/saml")
class SamlController {
    private final SamlMessageService samlMessageService;
    private final SamlProperties props;

    SamlController(SamlMessageService samlMessageService, SamlProperties props) {
        this.samlMessageService = samlMessageService;
        this.props = props;
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public String metadata() throws Exception {
        return samlMessageService.buildMetadata();
    }

    @GetMapping("/login")
    public void login(@RequestParam(value = "relayState", required = false, defaultValue = "/") String relayState,
                      HttpServletResponse response) throws Exception {
        String redirect = samlMessageService.buildAuthnRequest(relayState);
        response.sendRedirect(redirect);
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public void acs(@RequestParam("SAMLResponse") String samlResponse,
                    @RequestParam(value = "RelayState", required = false) String relayState,
                    HttpServletResponse response) throws Exception {
        String principal = samlMessageService.parseAndValidateSamlResponse(samlResponse);
        response.setStatus(HttpServletResponse.SC_OK);
        response.setContentType(MediaType.TEXT_PLAIN_VALUE);
        response.getWriter().write("Authenticated: " + principal + " relayState=" + relayState);
    }

    @GetMapping("/slo")
    public void slo(HttpServletRequest request, HttpServletResponse response) throws Exception {
        response.setStatus(HttpServletResponse.SC_OK);
        response.getWriter().write("Single Logout endpoint");
    }
}

class SamlApplication {
    public static void main(String[] args) throws Exception {
        InitializationService.initialize();
    }
}